#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=800005;
int n,m,tr[N][30],num[N],flag[N];
string s;
void push_down(int u)
{
	int ls=u*2,rs=u*2+1;
	for(int i=0;i<26;i++)
	{
		tr[ls][i]=tr[u][tr[ls][i]];
		tr[rs][i]=tr[u][tr[rs][i]];
	}
	for(int i=0;i<26;i++)
	{
		tr[u][i]=i;
	}
}
void build(int u,int l,int r)
{
	for(int i=0;i<26;i++)
	{
		tr[u][i]=i;
	}
	if(l==r)
	{
		num[l]=u;
        flag[u]=1;
		return ;
	}
	int mid=(l+r)/2;
	build(u*2,l,mid);
	build(u*2+1,mid+1,r);
}
void update(int u,int l,int r,int x,int y,int num1,int num2)// 将x~y区间的num1改为num2
{
	if(l>y||r<x) return ;
	if(l>=x&&r<=y)
	{
		for(int i=0;i<26;i++)
		{
			if(tr[u][i]==num1) tr[u][i]=num2;
		}
		return ;
	}
	push_down(u);
	int mid=(l+r)/2;
	update(u*2,l,mid,x,y,num1,num2);
	update(u*2+1,mid+1,r,x,y,num1,num2);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>s>>m;
	n=s.size();
	s=" "+s;
	build(1,1,n);
	for(int i=1;i<=m;i++)
	{
		int l,r;
		char a,b;
		cin>>l>>r>>a>>b;
		update(1,1,n,l,r,(int)(a-'a'),(int)(b-'a'));
	}
	for(int i=1;i<=4*n;i++)
	{
        if(flag[i]) continue;
		push_down(i);
	}
	for(int i=1;i<=n;i++)
	{
		cout<<(char)(tr[num[i]][(int)(s[i]-'a')]+'a');
	}
	return 0;
}
